 1	import { type FormEvent, type SyntheticEvent, useState } from 'react';
 2	
 3	import { InputGroup, SearchInput, ToolbarFilter } from '@patternfly/react-core';
 4	
 5	import type { FilterTypeProps } from './types';
 6	
 7	/**
 8	 * This Filter type uses an unsensitive-case text provided by the user.
 9	 * Text needs to be submitted/confirmed by clicking search button or by pressing Enter key.
10	 *
11	 * **FilterTypeProps are interpreted as follows** :<br>
12	 * 1) selectedFilters - list of strings provided by the user<br>
13	 * 2) onFilterUpdate - accepts the list of strings (from user input)
14	 *
15	 * [<img src="static/media/src/components-stories/assets/github-logo.svg"><i class="fi fi-brands-github">
16	 * <font color="green">View component source on GitHub</font>](https://github.com/kubev2v/forklift-console-plugin/blob/main/packages/common/src/components/Filter/FreetextFilter.tsx)
17	 */
18	export const FreetextFilter = ({
19	  filterId,
20	  onFilterUpdate,
21	  placeholderLabel,
22	  selectedFilters,
23	  showFilter = true,
24	  title,
25	}: FilterTypeProps) => {
26	  const [inputValue, setInputValue] = useState('');
27	
28	  const onTextInput: (
29	    event: SyntheticEvent<HTMLButtonElement>,
30	    value: string,
31	    attrValueMap: Record<string, string>,
32	  ) => void = () => {
33	    const lowerCaseInputValue = inputValue?.toLowerCase();
34	    if (!lowerCaseInputValue || selectedFilters.includes(lowerCaseInputValue)) {
35	      return;
36	    }
37	    onFilterUpdate([...selectedFilters, lowerCaseInputValue]);
38	    setInputValue('');
39	  };
40	
41	  const onChange: (event: FormEvent<HTMLInputElement>, value: string) => void = (_event, value) => {
42	    setInputValue(value);
43	  };
44	
45	  const onClear: (event: SyntheticEvent<HTMLButtonElement>) => void = () => {
46	    setInputValue('');
47	  };
48	
49	  return (
50	    <ToolbarFilter
51	      key={filterId}
52	      labels={selectedFilters ?? []}
53	      deleteLabel={(category, option) =>
54	        onFilterUpdate(selectedFilters?.filter((value) => value !== option) ?? [])
55	      }
56	      deleteLabelGroup={() => onFilterUpdate([])}
57	      categoryName={title}
58	      showToolbarItem={showFilter}
59	    >
60	      <InputGroup>
61	        <SearchInput
62	          placeholder={placeholderLabel}
63	          value={inputValue}
64	          onChange={onChange}
65	          onSearch={onTextInput}
66	          onClear={onClear}
67	        />
68	      </InputGroup>
69	    </ToolbarFilter>
70	  );
71	};

